    10→
    11→test('${testName}', async ({ page }) => {
    12→  const consoleErrors: string[] = [];
    13→  const networkFailures: { url: string; status: number }[] = [];
    14→
    15→  // Capture console errors
    16→  page.on('console', msg => {
    17→    if (msg.type() === 'error') {
    18→      consoleErrors.push(msg.text());
    19→    }
    20→  });
    21→
    22→  // Capture network failures
    23→  page.on('response', response => {
    24→    if (response.status() >= 400) {
    25→      networkFailures.push({
    26→        url: response.url(),
    27→        status: response.status(),
    28→      });
    29→    }
    30→  });
    31→
    32→  // Navigate to route
    33→  await page.goto('${url}');
    34→
    35→  // Wait for page to be ready
    36→  await page.waitForLoadState('networkidle');
    37→
    38→  // Take screenshot
    39→  await page.screenshot({ fullPage: true });
    40→
    41→  // Assert no console errors
    42→  expect(consoleErrors, 'Console errors detected').toHaveLength(0);
    43→
    44→  // Assert no network failures
    45→  expect(networkFailures, 'Network failures detected').toHaveLength(0);
    46→});
    47→`;
    48→}
